import React, { useState } from 'react';
import { loginAuth, registerAuth, getDemoAuthToken } from '../../services/api';
import { API_URL } from '../../utils/apiClient';
import useStore from '../../store/useStore';
import './Login.css';

export const LOGIN_STORAGE_KEY = 'hotel-login-state';

function saveLoginState(token, tenantId, role) {
  try {
    localStorage.setItem(LOGIN_STORAGE_KEY, JSON.stringify({
      token, tenantId: tenantId || 'default', role: role || 'owner', loggedInAt: Date.now(),
    }));
  } catch {}
}

export function clearLoginState() {
  try { localStorage.removeItem(LOGIN_STORAGE_KEY); } catch {}
}

// Reset password via backend
async function resetPasswordApi(email, newPassword) {
  const res = await fetch(`${API_URL}/api/auth/reset-password`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email, new_password: newPassword }),
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.error || 'Reset failed');
  return data;
}

// ─── Tabs ────────────────────────────────────────────────────────────────────
const TABS = ['login', 'register', 'reset'];
const TAB_LABELS = { login: 'כניסה', register: 'הרשמה', reset: 'שכחתי סיסמה' };

export default function LoginPage() {
  const { setAuthToken, setActiveTenantId, setRole } = useStore();

  const [tab, setTab]           = useState('login');
  const [email, setEmail]       = useState('levikobi40@gmail.com');
  const [password, setPassword] = useState('123456');
  const [newPass, setNewPass]   = useState('');
  const [confirm, setConfirm]   = useState('');
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState('');
  const [success, setSuccess]   = useState('');

  const handleSuccess = (data) => {
    if (!data?.token) { setError('לא התקבל טוקן מהשרת'); return; }
    setAuthToken(data.token);
    setActiveTenantId(data.tenant_id || 'default');
    setRole(data.role || 'owner');
    saveLoginState(data.token, data.tenant_id, data.role);
    // sync zustand store key too
    try {
      const raw = localStorage.getItem('hotel-enterprise-storage');
      const parsed = raw ? JSON.parse(raw) : { state: {}, version: 0 };
      parsed.state = {
        ...(parsed.state || {}),
        authToken: data.token,
        role: data.role || 'owner',
        activeTenantId: data.tenant_id || 'default',
      };
      localStorage.setItem('hotel-enterprise-storage', JSON.stringify(parsed));
    } catch {}
  };

  // ── Login ──────────────────────────────────────────────────────────────────
  const handleLogin = async (e) => {
    e.preventDefault();
    setError(''); setSuccess('');
    if (!email.trim()) { setError('נא להזין אימייל'); return; }
    if (!password)     { setError('נא להזין סיסמה'); return; }
    setLoading(true);
    try {
      const data = await loginAuth(email.trim().toLowerCase(), password);
      handleSuccess(data);
    } catch (err) {
      const msg = err?.message || '';
      if (msg.includes('Invalid credentials') || msg.includes('401')) {
        setError('אימייל או סיסמה שגויים. נסה שוב או לחץ על "שכחתי סיסמה".');
      } else if (msg.includes('fetch') || msg.includes('network') || msg.includes('Failed')) {
        setError(`לא ניתן להתחבר לשרת (${API_URL}). וודא ש-Python רץ על פורט 1000.`);
      } else {
        setError(msg || 'שגיאת כניסה');
      }
    } finally {
      setLoading(false);
    }
  };

  // ── Register ───────────────────────────────────────────────────────────────
  const handleRegister = async (e) => {
    e.preventDefault();
    setError(''); setSuccess('');
    if (!email.trim())       { setError('נא להזין אימייל'); return; }
    if (password.length < 6) { setError('הסיסמה חייבת לפחות 6 תווים'); return; }
    setLoading(true);
    try {
      const data = await registerAuth(email.trim().toLowerCase(), password);
      handleSuccess(data);
    } catch (err) {
      const msg = err?.message || '';
      if (msg.includes('already') || msg.includes('409')) {
        // Email exists → auto-switch to login and try
        setError('');
        setSuccess('האימייל כבר רשום. מנסה להיכנס אוטומטית...');
        try {
          const data = await loginAuth(email.trim().toLowerCase(), password);
          handleSuccess(data);
        } catch {
          setSuccess('');
          setError('האימייל כבר רשום אך הסיסמה שגויה. עבור ל"שכחתי סיסמה" כדי לאפס.');
          setTab('login');
        }
      } else if (msg.includes('fetch') || msg.includes('network') || msg.includes('Failed')) {
        setError(`לא ניתן להגיע לשרת (${API_URL}). וודא ש-Python רץ.`);
      } else {
        setError(msg || 'שגיאת הרשמה');
      }
    } finally {
      setLoading(false);
    }
  };

  // ── Reset password ─────────────────────────────────────────────────────────
  const handleReset = async (e) => {
    e.preventDefault();
    setError(''); setSuccess('');
    if (!email.trim())       { setError('נא להזין אימייל'); return; }
    if (newPass.length < 6)  { setError('הסיסמה החדשה חייבת לפחות 6 תווים'); return; }
    if (newPass !== confirm)  { setError('הסיסמאות אינן תואמות'); return; }
    setLoading(true);
    try {
      const data = await resetPasswordApi(email.trim().toLowerCase(), newPass);
      handleSuccess(data);
      setSuccess('הסיסמה אופסה בהצלחה! נכנס...');
    } catch (err) {
      const msg = err?.message || '';
      if (msg.includes('not found') || msg.includes('404')) {
        setError('האימייל לא קיים במערכת. עבור להרשמה.');
      } else {
        setError(msg || 'שגיאת איפוס');
      }
    } finally {
      setLoading(false);
    }
  };

  // ── Dev bypass (no server needed) ─────────────────────────────────────────
  const handleDevLogin = () => {
    setError(''); setSuccess('');
    const token = 'dev-bypass-' + Date.now();
    handleSuccess({ token, tenant_id: 'default', role: 'admin' });
  };

  // ── Demo (calls /api/auth/demo) ────────────────────────────────────────────
  const handleDemo = async () => {
    setError(''); setSuccess('');
    setLoading(true);
    try {
      const data = await getDemoAuthToken('demo');
      handleSuccess({ ...data, role: data.role || 'owner' });
    } catch (err) {
      setError(err?.message || 'שגיאת כניסת דמו');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="lp-screen">
      <div className="lp-card">

        {/* Logo / Title */}
        <div className="lp-header">
          <div className="lp-logo">🏨</div>
          <h1 className="lp-title">EasyHost</h1>
          <p className="lp-subtitle">מערכת ניהול נכסים חכמה</p>
        </div>

        {/* Default credentials hint */}
        <div className="lp-hint-box">
          <span className="lp-hint-icon">💡</span>
          <div>
            <strong>חשבון מנהל:</strong> levikobi40@gmail.com<br />
            <strong>סיסמה:</strong> 123456
          </div>
        </div>

        {/* Tabs */}
        <div className="lp-tabs">
          {TABS.map(t => (
            <button
              key={t}
              className={`lp-tab ${tab === t ? 'lp-tab--active' : ''}`}
              onClick={() => { setTab(t); setError(''); setSuccess(''); }}
            >
              {TAB_LABELS[t]}
            </button>
          ))}
        </div>

        {/* ── LOGIN ── */}
        {tab === 'login' && (
          <form className="lp-form" onSubmit={handleLogin} noValidate>
            <input
              className="lp-input" type="email" placeholder="אימייל"
              value={email} onChange={e => setEmail(e.target.value)}
              autoComplete="email" dir="ltr"
            />
            <input
              className="lp-input" type="password" placeholder="סיסמה"
              value={password} onChange={e => setPassword(e.target.value)}
              autoComplete="current-password" dir="ltr"
            />
            {error   && <p className="lp-msg lp-msg--error">{error}</p>}
            {success && <p className="lp-msg lp-msg--success">{success}</p>}
            <button className="lp-btn lp-btn--primary" type="submit" disabled={loading}>
              {loading ? '⏳ מתחבר...' : '🔑 כניסה'}
            </button>
          </form>
        )}

        {/* ── REGISTER ── */}
        {tab === 'register' && (
          <form className="lp-form" onSubmit={handleRegister} noValidate>
            <input
              className="lp-input" type="email" placeholder="אימייל"
              value={email} onChange={e => setEmail(e.target.value)}
              autoComplete="email" dir="ltr"
            />
            <input
              className="lp-input" type="password" placeholder="סיסמה (לפחות 6 תווים)"
              value={password} onChange={e => setPassword(e.target.value)}
              autoComplete="new-password" dir="ltr"
            />
            {error   && <p className="lp-msg lp-msg--error">{error}</p>}
            {success && <p className="lp-msg lp-msg--success">{success}</p>}
            <button className="lp-btn lp-btn--primary" type="submit" disabled={loading}>
              {loading ? '⏳ נרשם...' : '✅ הרשמה'}
            </button>
          </form>
        )}

        {/* ── RESET ── */}
        {tab === 'reset' && (
          <form className="lp-form" onSubmit={handleReset} noValidate>
            <p className="lp-hint">הזן את האימייל שלך וסיסמה חדשה לאיפוס</p>
            <input
              className="lp-input" type="email" placeholder="אימייל"
              value={email} onChange={e => setEmail(e.target.value)}
              autoComplete="email" dir="ltr"
            />
            <input
              className="lp-input" type="password" placeholder="סיסמה חדשה"
              value={newPass} onChange={e => setNewPass(e.target.value)}
              autoComplete="new-password" dir="ltr"
            />
            <input
              className="lp-input" type="password" placeholder="אשר סיסמה חדשה"
              value={confirm} onChange={e => setConfirm(e.target.value)}
              autoComplete="new-password" dir="ltr"
            />
            {error   && <p className="lp-msg lp-msg--error">{error}</p>}
            {success && <p className="lp-msg lp-msg--success">{success}</p>}
            <button className="lp-btn lp-btn--primary" type="submit" disabled={loading}>
              {loading ? '⏳ מאפס...' : '🔄 אפס סיסמה'}
            </button>
          </form>
        )}

        {/* ── Divider ── */}
        <div className="lp-divider"><span>או</span></div>

        {/* ── Quick access ── */}
        <button className="lp-btn lp-btn--admin" onClick={() => {
          setEmail('levikobi40@gmail.com');
          setPassword('123456');
          setTab('login');
          setTimeout(() => {
            loginAuth('levikobi40@gmail.com', '123456')
              .then(handleSuccess)
              .catch(e => setError(e.message));
          }, 50);
        }} disabled={loading}>
          👑 כניסה מהירה כמנהל
        </button>
        <button className="lp-btn lp-btn--demo" onClick={handleDemo} disabled={loading}>
          🚀 כניסת דמו (ללא הרשמה)
        </button>
        <button className="lp-btn lp-btn--dev" onClick={handleDevLogin}>
          ⚡ כניסה מיידית [Dev] (ללא שרת)
        </button>

      </div>
    </div>
  );
}
